arguments.command:
export PATH="$PATH:$HOME/.dotnet/tools"
# Let me use a .NET script to parse the binlog properly
cat > /tmp/parse_binlog.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net9.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.415" />
  </ItemGroup>
</Project>
EOF

cat > /tmp/parse_binlog.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild("/tmp/sv-f5dff43a33c24b1aa5890fd97f5912b0/build.binlog");
var errors = new List<(string project, string code, string message, string file, int line)>();

build.VisitAllChildren<Error>(error => {
    var project = "";
    var parent = error.Parent;
    while (parent != null) {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    errors.Add((project, error.Code ?? "", error.Text ?? error.ToString(), error.File ?? "", error.LineNumber));
});

Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

foreach (var g in errors.GroupBy(e => e.project)) {
    Console.WriteLine($"=== Project: {g.Key} ===");
    foreach (var e in g) {
        Console.WriteLine($"  [{e.code}] {e.file}({e.line}): {e.message}");
    }
    Console.WriteLine();
}
EOF

