cd /tmp/binlog_parser && cat > Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild("/tmp/sv-f5dff43a33c24b1aa5890fd97f5912b0/build.binlog");

// Check warnings too
var warnings = new List<(string project, string code, string message)>();
build.VisitAllChildren<Warning>(w => {
    var project = "";
    var parent = w.Parent;
    while (parent != null) {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    if (w.Code != null && (w.Code.StartsWith("NU") || w.Code.StartsWith("CS") || w.Code.StartsWith("MSB")))
        warnings.Add((project, w.Code, w.Text ?? ""));
});

Console.WriteLine("=== NuGet/MSBuild Warnings ===");
foreach (var w in warnings.Where(w => w.code.StartsWith("NU") || w.code.StartsWith("MSB"))) {
    Console.WriteLine($"  [{w.code}] {w.project}: {w.message}");
}

// Check project references  
Console.WriteLine("\n=== Build Results per Project ===");
build.VisitAllChildren<Project>(p => {
    if (p.Name.EndsWith(".csproj") || p.Name.EndsWith(".metaproj"))
        Console.WriteLine($"  {p.Name} -> Succeeded={p.Succeeded}");
});

// Reconstruct source files if possible
Console.WriteLine("\n=== Reconstructing source files ===");
build.VisitAllChildren<SourceFile>(sf => {
    Console.WriteLine($"  {sf.Name}");
});
EOF
